def merge_within(pairs, d):
    if not pairs:
        return []

    merged = []
    pairs.sort()

    for start, end in pairs:
        if not merged or start > merged[-1][1] + d:
            merged.append([start, end])
        else:
            merged[-1][1] = max(merged[-1][1], end)

    return merged
